def log(level, *messages, **extra):
    prefix = f'[{level}]'
    for msg in messages:
        print(f'{prefix} {msg}')
    for k, v in extra.items():
        print(f'  {k}={v}')

log('INFO', 'Запуск', 'Ініціалізація', user='admin', pid=1234)
